73	func (f *CommandFactory) newAgentWorkersCommand() *cobra.Command {
74		cmd := &cobra.Command{
75			Use:   "workers",
76			Short: "Show running agent workers and their current bead",
77			Long: `Show all running agent workers and the bead each is currently executing.
78	
79	Server-submitted workers (started via 'ddx agent execute-loop') are fetched from
80	the running ddx server. Local workers (started with --local) are detected by
81	scanning active execute-bead worktrees in the project.
82	
83	Examples:
84	  ddx agent workers
85	  ddx agent workers --json
86	  ddx agent workers --watch
87	  ddx agent workers --project /path/to/project`,
88			Args: cobra.NoArgs,
89			RunE: f.runAgentWorkers,
90		}
91		cmd.Flags().Bool("json", false, "Emit raw JSON array")
92		cmd.Flags().Bool("watch", false, "Re-render every 2s until Ctrl-C")
93		cmd.Flags().String("project", "", "Project root to query (default: detected from CWD)")
94	
95		cmd.AddCommand(f.newAgentWorkersStopCommand())
96		return cmd
97	}
