136	func (f *CommandFactory) runAgentWorkersStop(cmd *cobra.Command, args []string) error {
137		allOver, _ := cmd.Flags().GetDuration("all-over")
138		stateFilter, _ := cmd.Flags().GetString("state")
139		beadFilter, _ := cmd.Flags().GetString("bead")
140		projectFlag, _ := cmd.Flags().GetString("project")
141		asJSON, _ := cmd.Flags().GetBool("json")
142	
143		// Enforce that the operator picks exactly one targeting mode.
144		modes := 0
145		if len(args) > 0 {
146			modes++
147		}
148		if allOver > 0 {
149			modes++
150		}
151		if stateFilter != "" {
152			modes++
153		}
154		if beadFilter != "" {
155			modes++
156		}
157		if modes == 0 {
158			return fmt.Errorf("specify a worker id or one of --all-over, --state, --bead")
159		}
160		if modes > 1 {
161			return fmt.Errorf("specify exactly one of: <worker-id>, --all-over, --state, --bead")
162		}
163	
164		projectRoot := projectFlag
165		if projectRoot == "" {
166			projectRoot = gitpkg.FindProjectRoot(f.WorkingDir)
167		}
168	
169		var targets []string
170		if len(args) > 0 {
171			targets = []string{args[0]}
172		} else {
173			workers := collectAgentWorkers(projectRoot)
174			now := time.Now()
175			for _, wk := range workers {
176				if wk.Kind == "local" {
177					// Local (execute-bead) workers are not reachable through the
178					// server stop endpoint. Skip them here — operators must stop
179					// them via the worktree's own lifecycle.
180					continue
181				}
182				if allOver > 0 {
183					if wk.State != "running" || wk.StartedAt.IsZero() {
184						continue
185					}
186					if now.Sub(wk.StartedAt) <= allOver {
187						continue
188					}
189				}
190				if stateFilter != "" && wk.State != stateFilter {
191					continue
192				}
193				if beadFilter != "" && wk.BeadID != beadFilter {
194					continue
195				}
196				targets = append(targets, wk.ID)
197			}
198		}
199	
200		if len(targets) == 0 {
201			fmt.Fprintln(cmd.OutOrStdout(), "no matching workers")
202			return nil
203		}
204	
205		base := resolveServerURL(projectRoot)
206		client := newLocalServerClient()
207	
208		var firstErr error
209		for _, id := range targets {
210			reqURL := base + "/api/agent/workers/" + id + "/stop"
211			req, err := http.NewRequestWithContext(cmd.Context(), http.MethodPost, reqURL, nil)
212			if err != nil {
213				if firstErr == nil {
214					firstErr = err
215				}
216				continue
217			}
218			resp, err := client.Do(req)
219			if err != nil {
220				fmt.Fprintf(cmd.ErrOrStderr(), "stop %s: %v\n", id, err)
221				if firstErr == nil {
222					firstErr = err
223				}
224				continue
225			}
226			body, _ := io.ReadAll(resp.Body)
227			_ = resp.Body.Close()
228			if resp.StatusCode != http.StatusOK {
229				msg := strings.TrimSpace(string(body))
230				fmt.Fprintf(cmd.ErrOrStderr(), "stop %s: server error (%d): %s\n", id, resp.StatusCode, msg)
231				if firstErr == nil {
232					firstErr = fmt.Errorf("server error (%d) for %s", resp.StatusCode, id)
233				}
234				continue
235			}
236			if asJSON {
237				fmt.Fprintln(cmd.OutOrStdout(), strings.TrimSpace(string(body)))
238			} else {
239				fmt.Fprintf(cmd.OutOrStdout(), "stopping %s\n", id)
240			}
241		}
242		return firstErr
243	}
