286	// collectAgentWorkers fetches workers from the server and local manifest scan,
287	// merges and deduplicates them, and returns the unified list.
288	func collectAgentWorkers(projectRoot string) []agentWorkerDisplay {
289		serverWorkers, serverAttemptIDs := fetchServerAgentWorkers(projectRoot)
290		localWorkers := scanLocalBeadWorkers(projectRoot, serverAttemptIDs)
291	
292		result := make([]agentWorkerDisplay, 0, len(serverWorkers)+len(localWorkers))
293		result = append(result, serverWorkers...)
294		result = append(result, localWorkers...)
295		return result
296	}
