298	// fetchServerAgentWorkers calls GET /api/agent/workers and converts the
299	// response to display records. Returns a set of attempt IDs already covered
300	// by the server so local scanning can skip them.
301	func fetchServerAgentWorkers(projectRoot string) ([]agentWorkerDisplay, map[string]bool) {
302		base := resolveServerURL(projectRoot)
303		client := newLocalServerClient()
304		resp, err := client.Get(base + "/api/agent/workers")
305		if err != nil {
306			return nil, nil
307		}
308		defer resp.Body.Close() //nolint:errcheck
309	
310		var records []agentWorkerServerRecord
311		if err := json.NewDecoder(resp.Body).Decode(&records); err != nil {
312			return nil, nil
313		}
314	
315		out := make([]agentWorkerDisplay, 0, len(records))
316		attemptIDs := make(map[string]bool)
317	
318		for _, r := range records {
319			d := agentWorkerDisplay{
320				ID:        r.ID,
321				Kind:      r.Kind,
322				State:     r.State,
323				Harness:   r.Harness,
324				Model:     r.Model,
325				StartedAt: r.StartedAt,
326				Attempts:  r.Attempts,
327				Successes: r.Successes,
328				Failures:  r.Failures,
329				PID:       r.PID,
330			}
331			if d.Kind == "" {
332				d.Kind = "server"
333			}
334			if r.CurrentAttempt != nil {
335				d.BeadID = r.CurrentAttempt.BeadID
336				d.BeadTitle = r.CurrentAttempt.BeadTitle
337				if r.CurrentAttempt.Harness != "" {
338					d.Harness = r.CurrentAttempt.Harness
339				}
340				if r.CurrentAttempt.Model != "" {
341					d.Model = r.CurrentAttempt.Model
342				}
343				d.ElapsedMS = r.CurrentAttempt.ElapsedMS
344				attemptIDs[r.CurrentAttempt.AttemptID] = true
345			} else if r.LastResult != nil && r.LastResult.BeadID != "" {
346				d.BeadID = r.LastResult.BeadID
347			} else if r.CurrentBead != "" {
348				d.BeadID = r.CurrentBead
349			}
350			out = append(out, d)
351		}
352		return out, attemptIDs
353	}
