1103	// Stop performs a graceful termination of the worker:
1104	//  1. Mark state=stopping and persist so observers see the transition.
1105	//  2. Emit bead.stopped event + release the bead claim (if one is held).
1106	//  3. Send SIGTERM to the worker's process group; escalate to SIGKILL
1107	//     after WatchdogKillGrace if the leader is still alive. Pure-goroutine
1108	//     workers have no PID — ctx cancellation below is the only lever.
1109	//  4. Cancel the worker's context so the loop and in-flight executor exit.
1110	//  5. Mark state=stopped and persist. runWorker preserves this terminal
1111	//     state when it writes its final record.
1112	//
1113	// Stop is idempotent: a second call is a no-op. It returns an error only
1114	// when the worker is unknown to the manager (already exited / never existed).
1115	func (m *WorkerManager) Stop(id string) error {
1116		m.mu.Lock()
1117		handle := m.workers[id]
1118		if handle == nil || handle.cancel == nil {
1119			m.mu.Unlock()
1120			return fmt.Errorf("worker not running")
1121		}
1122		if handle.stopped {
1123			m.mu.Unlock()
1124			return nil
1125		}
1126		handle.stopped = true
1127	
1128		now := time.Now().UTC()
1129		projectRoot := handle.record.ProjectRoot
1130		if projectRoot == "" {
1131			projectRoot = m.projectRoot
1132		}
1133		pid := handle.record.PID
1134		beadID := ""
1135		if handle.record.CurrentAttempt != nil {
1136			beadID = handle.record.CurrentAttempt.BeadID
1137		}
1138		if beadID == "" {
