2066	// resolveRequestedProject matches a requested project_root string against
2067	// registered projects. It tries exact path match first, then name (basename)
2068	// match. Returns the canonical path on success, or "" if no match or ambiguous.
2069	func (s *Server) resolveRequestedProject(requested string) string {
2070		// Exact path match via the state's lookup method.
2071		if entry, ok := s.state.GetProjectByPath(requested); ok {
2072			return entry.Path
2073		}
2074		// Name (basename) match — only unambiguous if exactly one project has that name.
2075		projects := s.state.GetProjects()
2076		var matches []string
2077		for _, p := range projects {
2078			if p.Name == requested {
2079				matches = append(matches, p.Path)
2080			}
2081		}
2082		if len(matches) == 1 {
2083			return matches[0]
2084		}
2085		return ""
2086	}
