// scanLocalBeadWorkers scans .ddx/executions/*/manifest.json and checks
// active git worktrees to find locally-running execute-bead executions
// not already covered by the server.
//
// Stale entries — the worktree is still registered but the recorded PID
// is dead — are returned with state="stale" and PIDAlive=false so
// operators can see and reap them via `ddx agent workers prune`. Without
// this, a crashed execute-bead leaves the worktree behind and the entry
// would either disappear silently (hiding the leaked worktree) or
// pretend to be running forever (the bug this commit fixes).
func scanLocalBeadWorkers(projectRoot string, serverAttemptIDs map[string]bool) []agentWorkerDisplay {
	execDir := filepath.Join(projectRoot, ".ddx", "executions")
