		// Skip if worker_id is set — server-submitted executions are in the server list
		if m.WorkerID != "" {
			continue
		}

		// Check if the worktree for this attempt is still active. A
		// missing worktree means the entry has already been cleaned up
		// (either by a successful run's teardown, or a previous prune)
		// and we have nothing to surface.
		wtPath := agentLocalWorktreePath(m.BeadID, m.AttemptID)
		if !active[wtPath] {
			continue
		}

		// Liveness — only meaningful when a PID was recorded. Older
		// manifests written before the PID field landed leave alive nil
		// (unknown). We treat unknown as "running" for backward compat.
		var alive *bool
		state := "running"
		if m.PID > 0 {
			a := agentProcessAlive(m.PID)
			alive = &a
			if !a {
				state = "stale"
			}
		}

		elapsed := time.Since(m.CreatedAt)
		d := agentWorkerDisplay{
			ID:          "local-" + m.AttemptID,
			Kind:        "local",
			State:       state,
			BeadID:      m.BeadID,
			BeadTitle:   m.Bead.Title,
			Harness:     m.Requested.Harness,
			Model:       m.Requested.Model,
			StartedAt:   m.CreatedAt,
			ElapsedMS:   elapsed.Milliseconds(),
			PID:         m.PID,
			PIDAlive:    alive,
			AttemptID:   m.AttemptID,
			ProjectRoot: projectRoot,
		}
		out = append(out, d)
	}
	return out
}

