//go:build !windows

package cmd

import "syscall"

// agentProcessAlive reports whether a process with the given PID is
// currently alive. Signal 0 probes existence without sending an actual
// signal — ESRCH is the canonical "no such process" reply, anything else
// (nil, EPERM) means the process exists.
func agentProcessAlive(pid int) bool {
	if pid <= 0 {
		return false
	}
	err := syscall.Kill(pid, 0)
	return err != syscall.ESRCH
}

//go:build windows

package cmd

import "os"

// agentProcessAlive reports whether a process with the given PID is
// currently alive. On Windows os.FindProcess always succeeds, so the
// best portable signal we have is "did we get a handle" — we treat any
// successful FindProcess as alive. Operators on Windows can still prune
// by --older-than to reap entries that no longer correspond to any
// running ddx worker.
func agentProcessAlive(pid int) bool {
	if pid <= 0 {
		return false
	}
	p, err := os.FindProcess(pid)
	if err != nil {
		return false
	}
	_ = p
	return true
}

