// newAgentWorkersPruneCommand wires the `ddx agent workers prune` subcommand
// for reaping stale registry entries left behind by execute-bead/execute-loop
// processes that exited abnormally.
//
// Targeting:
//
//	ddx agent workers prune                 — reap entries whose PID is dead
//	ddx agent workers prune --older-than 6h — also reap entries older than <d>
//	ddx agent workers prune --dry-run       — list what would be reaped, change nothing
//	ddx agent workers prune --json          — emit one JSON object per reaped worker
//
// For local workers the prune path removes the git worktree and returns the
// registry slot. For server workers it routes through the existing stop
// endpoint, which is how the server's WorkerManager releases its in-memory
// handle and rewrites the persisted record. The two paths surface the same
// summary so operators see one consistent answer for both kinds.
func (f *CommandFactory) newAgentWorkersPruneCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "prune",
		Short: "Reap stale agent worker registry entries",
		Long: `Reap registry entries whose recorded PID is no longer alive (or whose
started_at is older than --older-than). Useful when an execute-bead or
execute-loop process exits abnormally — the worker entry would otherwise
be stuck in state=running forever, with elapsed_ms continuously
advancing, polluting ` + "`ddx agent workers`" + ` output and confusing
operators trying to triage the queue.

Local workers: the matching git worktree is removed so future scans no
longer surface the entry. Server workers: routed through the same stop
endpoint as ` + "`ddx agent workers stop`" + ` so the in-memory handle
and persisted status.json record are released cleanly.`,
		Args: cobra.NoArgs,
		RunE: f.runAgentWorkersPrune,
	}
	cmd.Flags().Duration("older-than", 0, "Also reap entries whose started_at is older than this duration")
	cmd.Flags().Bool("dry-run", false, "List what would be reaped without changing anything")
	cmd.Flags().Bool("json", false, "Emit one JSON object per reaped worker")
	cmd.Flags().String("project", "", "Project root to query (default: detected from CWD)")
	return cmd
}

// agentWorkerPruneEntry is the per-reap output record. Stays minimal so
// scripts can pipe `prune --json` directly into jq filters.
type agentWorkerPruneEntry struct {
	ID        string        `json:"id"`
	Kind      string        `json:"kind"`
	BeadID    string        `json:"bead_id,omitempty"`
	Harness   string        `json:"harness,omitempty"`
	Age       time.Duration `json:"-"`
	AgeText   string        `json:"age,omitempty"`
	Reason    string        `json:"reason"`
	DryRun    bool          `json:"dry_run,omitempty"`
	StatusErr string        `json:"error,omitempty"`
}

func (f *CommandFactory) runAgentWorkersPrune(cmd *cobra.Command, _ []string) error {
	olderThan, _ := cmd.Flags().GetDuration("older-than")
	dryRun, _ := cmd.Flags().GetBool("dry-run")
	asJSON, _ := cmd.Flags().GetBool("json")
	projectFlag, _ := cmd.Flags().GetString("project")

	projectRoot := projectFlag
	if projectRoot == "" {
		projectRoot = gitpkg.FindProjectRoot(f.WorkingDir)
	}

	workers := collectAgentWorkers(projectRoot)
	now := time.Now()

	var reaped []agentWorkerPruneEntry
	for _, wk := range workers {
		reason := ""
		if wk.PIDAlive != nil && !*wk.PIDAlive {
			reason = "pid-dead"
		}
		var age time.Duration
		if !wk.StartedAt.IsZero() {
			age = now.Sub(wk.StartedAt)
		}
		if reason == "" && olderThan > 0 && age > olderThan {
			reason = "older-than"
		}
		if reason == "" {
			continue
		}

		entry := agentWorkerPruneEntry{
			ID:      wk.ID,
			Kind:    wk.Kind,
			BeadID:  wk.BeadID,
			Harness: wk.Harness,
			Age:     age,
			AgeText: age.Round(time.Second).String(),
			Reason:  reason,
			DryRun:  dryRun,
		}

		if !dryRun {
			if err := pruneAgentWorker(cmd.Context(), projectRoot, wk); err != nil {
				entry.StatusErr = err.Error()
			}
		}
		reaped = append(reaped, entry)
	}

	if len(reaped) == 0 {
		fmt.Fprintln(cmd.OutOrStdout(), "no stale workers")
		return nil
	}

	if asJSON {
		enc := json.NewEncoder(cmd.OutOrStdout())
		enc.SetIndent("", "  ")
		return enc.Encode(reaped)
	}

	tw := tabwriter.NewWriter(cmd.OutOrStdout(), 0, 0, 2, ' ', 0)
	header := "ID\tBEAD\tHARNESS\tAGE\tREASON"
	if dryRun {
		header = "[dry-run] " + header
	}
	fmt.Fprintln(tw, header)
	for _, e := range reaped {
		bead := e.BeadID
		if bead == "" {
			bead = "-"
		}
		harness := e.Harness
		if harness == "" {
			harness = "-"
		}
		row := fmt.Sprintf("%s\t%s\t%s\t%s\t%s", e.ID, bead, harness, e.AgeText, e.Reason)
		if e.StatusErr != "" {
			row += "\terror=" + e.StatusErr
		}
		fmt.Fprintln(tw, row)
	}
	return tw.Flush()
}

// pruneAgentWorker reaps a single worker entry. Local workers shed their
// worktree directly (nothing else holds the registry slot); server workers
// route through the stop endpoint so WorkerManager.Stop releases the
// in-memory handle and rewrites status.json.
func pruneAgentWorker(ctx context.Context, projectRoot string, wk agentWorkerDisplay) error {
	if wk.Kind == "local" {
		return removeStaleLocalWorker(projectRoot, wk)
	}
	return stopServerWorker(ctx, projectRoot, wk.ID)
}

// removeStaleLocalWorker reaps a stale local execute-bead worker. It best-
// effort kills the recorded PID (in case it's actually a zombie still
// hanging around), removes the registered git worktree, and prunes any
// orphaned git metadata. The execution evidence under
// .ddx/executions/<id>/ is left intact — that's the bead's audit trail.
func removeStaleLocalWorker(projectRoot string, wk agentWorkerDisplay) error {
	if wk.AttemptID == "" {
		return fmt.Errorf("local worker %s missing attempt_id; cannot locate worktree", wk.ID)
	}
	if wk.PID > 0 && wk.PIDAlive != nil && *wk.PIDAlive {
		// A live PID on a "stale" entry only happens with --older-than;
		// kill the leader so the worktree isn't held open. Best effort —
		// downstream worktree-remove cleans up the git side either way.
		if p, err := os.FindProcess(wk.PID); err == nil {
			_ = p.Signal(os.Interrupt)
		}
	}
	wtPath := agentLocalWorktreePath(wk.BeadID, wk.AttemptID)
	// Force removal — the worktree may have local edits, but the bead has
	// already exited and operators are calling prune to take that loss.
	if err := gitpkg.Command(context.Background(), projectRoot, "worktree", "remove", "--force", wtPath).Run(); err != nil {
		// Fall through to prune even on remove failure: prune cleans up
		// half-registered worktrees that remove won't touch.
		_ = gitpkg.Command(context.Background(), projectRoot, "worktree", "prune").Run()
		// If the path itself is gone, treat as success.
		if _, statErr := os.Stat(wtPath); os.IsNotExist(statErr) {
			return nil
		}
		return fmt.Errorf("removing worktree %s: %w", wtPath, err)
	}
	_ = gitpkg.Command(context.Background(), projectRoot, "worktree", "prune").Run()
	return nil
}

// stopServerWorker POSTs /api/agent/workers/{id}/stop. Used by both stop and
// prune so a single server contract owns the in-memory cleanup path.
//
// On HTTP 400 with body "worker not running" we treat the response as
// already-cleaned: the in-memory handle is gone, so there is nothing left to
// release. This is the contract that resolves the
// "registry says running, stop says not running" deadlock from the bug
// report.
func stopServerWorker(ctx context.Context, projectRoot, id string) error {
	base := resolveServerURL(projectRoot)
	client := newLocalServerClient()
	req, err := http.NewRequestWithContext(ctx, http.MethodPost, base+"/api/agent/workers/"+id+"/stop", nil)
	if err != nil {
		return err
	}
	resp, err := client.Do(req)
	if err != nil {
		return err
	}
	defer resp.Body.Close() //nolint:errcheck
	body, _ := io.ReadAll(resp.Body)
	if resp.StatusCode == http.StatusOK {
		return nil
	}
	msg := strings.TrimSpace(string(body))
	if resp.StatusCode == http.StatusBadRequest && strings.Contains(msg, "worker not running") {
		return nil
	}
	return fmt.Errorf("server error (%d): %s", resp.StatusCode, msg)
}

