// reconcileStaleRecord handles the "registry says running but in-memory
// handle is gone" case for an explicit Stop. The most common cause is a
// crashed or post-restart worker whose status.json was never rewritten.
// We consider the record reconcilable if (a) the persisted state is one
// of the live ones and (b) the recorded PID is dead (or absent). For a
// reconcilable record we rewrite status.json to state=stopped, append a
// lifecycle entry, and release any held bead claim. For a record that
// looks legitimately live (PID is alive but somehow not in memory — a
// process that escaped this manager's control) we still return the
// original "worker not running" error so operators don't accidentally
// release a claim under a running process.
func (m *WorkerManager) reconcileStaleRecord(id string) error {
	dir := filepath.Join(m.rootDir, id)
	rec, err := m.readRecord(dir)
	if err != nil {
		return fmt.Errorf("worker not running")
	}
	live := rec.State == "running" || rec.State == "starting" || rec.State == "stopping"
	if !live {
		// Already terminal — nothing to do, treat as no-op.
		return nil
	}
	if rec.PID > 0 && processAlive(rec.PID) {
		// The process really is alive but we lost track of it. Refuse
		// to release the claim — the operator should investigate.
		return fmt.Errorf("worker not running")
	}

	now := time.Now().UTC()
	beadID := ""
	if rec.CurrentAttempt != nil {
		beadID = rec.CurrentAttempt.BeadID
	}
	if beadID == "" {
		beadID = rec.CurrentBead
	}
	projectRoot := rec.ProjectRoot
	if projectRoot == "" {
		projectRoot = m.projectRoot
	}
	if beadID != "" {
		store := bead.NewStore(filepath.Join(projectRoot, ".ddx"))
		runtime := time.Duration(0)
		if !rec.StartedAt.IsZero() {
			runtime = now.Sub(rec.StartedAt)
		}
		body := fmt.Sprintf("worker=%s runtime=%s pid=%d reason=stale-stop",
			id, runtime.Round(time.Second), rec.PID)
		_ = store.AppendEvent(beadID, bead.BeadEvent{
			Kind:      "bead.stopped",
			Summary:   "stop",
			Body:      body,
			Actor:     "ddx",
			Source:    "server-workers",
			CreatedAt: now,
		})
		_ = store.Unclaim(beadID)
	}

	rec.State = "stopped"
	rec.Status = "stopped"
	if rec.FinishedAt.IsZero() {
		rec.FinishedAt = now
	}
	rec.CurrentAttempt = nil
	rec.Lifecycle = append(rec.Lifecycle, WorkerLifecycleEvent{
		Action:    "stop",
		Actor:     "local-operator",
		Timestamp: now,
		Detail:    fmt.Sprintf("reason=stale-reconcile pid=%d", rec.PID),
		BeadID:    beadID,
	})
	return m.writeRecord(dir, rec)
}

// processAlive is the package-private liveness probe used by Stop and the
// startup reconciler. Wrapped in a function so the unix/windows split lives
// alongside terminateProcessGroup in workers_reap_*.go.
//
// ReconcileOnStartup walks the persisted status.json files and downgrades
// any record whose state still reads "running" but whose process is dead.
// Called once during NewWorkerManager so a server restart can never leave
// orphan records perpetually claiming "running" with elapsed_ms ticking
// upward — the bug pattern from the issue report.
func (m *WorkerManager) ReconcileOnStartup() {
	if err := os.MkdirAll(m.rootDir, 0o755); err != nil {
		return
	}
	entries, err := os.ReadDir(m.rootDir)
	if err != nil {
		return
	}
	for _, entry := range entries {
		if !entry.IsDir() {
			continue
		}
		dir := filepath.Join(m.rootDir, entry.Name())
		rec, err := m.readRecord(dir)
		if err != nil {
			continue
		}
		if rec.State != "running" && rec.State != "starting" && rec.State != "stopping" {
			continue
		}
		// In a fresh manager nothing is in memory yet, so any
		// non-terminal persisted state is by definition orphaned. Use
		// PID liveness as the tiebreaker: live PID stays as-is (the
		// process survived us — let the watchdog handle it); dead or
		// missing PID is downgraded to "orphaned" so List() reports
		// reality and prune can sweep it.
		if rec.PID > 0 && processAlive(rec.PID) {
			continue
		}
		now := time.Now().UTC()
		rec.State = "orphaned"
		rec.Status = "orphaned"
		if rec.FinishedAt.IsZero() {
			rec.FinishedAt = now
		}
		rec.Lifecycle = append(rec.Lifecycle, WorkerLifecycleEvent{
			Action:    "reconcile",
			Actor:     "ddx-server",
			Timestamp: now,
			Detail:    fmt.Sprintf("reason=startup-reconcile pid=%d", rec.PID),
		})
		_ = m.writeRecord(dir, rec)
	}
}

