	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// initLocalWorkerRepo sets up a git repository and a single execute-bead
// manifest+worktree pair so the cmd-level worker scan has something to find.
// Returns the project root and the per-attempt manifest path so tests can
// mutate the recorded PID to simulate alive vs dead processes.
func initLocalWorkerRepo(t *testing.T, beadID, attemptID string, pid int) (projectRoot, manifestPath, worktreePath string) {
	t.Helper()
	projectRoot = t.TempDir()

	run := func(args ...string) {
		c := exec.Command("git", args...)
		c.Dir = projectRoot
		c.Env = append(os.Environ(),
			"GIT_AUTHOR_NAME=test", "GIT_AUTHOR_EMAIL=test@example.com",
			"GIT_COMMITTER_NAME=test", "GIT_COMMITTER_EMAIL=test@example.com",
		)
		out, err := c.CombinedOutput()
		require.NoErrorf(t, err, "git %s: %s", strings.Join(args, " "), string(out))
	}

	run("init", "-b", "main", projectRoot)
	require.NoError(t, os.WriteFile(filepath.Join(projectRoot, "README.md"), []byte("hi"), 0o644))
	run("-C", projectRoot, "add", "README.md")
	run("-C", projectRoot, "commit", "-m", "init")

	// Point execute-bead worktrees at a per-test temp directory so the
	// scan looks in a sandboxed location and not the global $TMPDIR.
	wtBase := filepath.Join(projectRoot, ".wt")
	require.NoError(t, os.MkdirAll(wtBase, 0o755))
	t.Setenv("DDX_EXEC_WT_DIR", wtBase)

	worktreePath = filepath.Join(wtBase, agent.ExecuteBeadWtPrefix+beadID+"-"+attemptID)
	run("-C", projectRoot, "worktree", "add", "-d", worktreePath)

	manifestDir := filepath.Join(projectRoot, ".ddx", "executions", attemptID)
	require.NoError(t, os.MkdirAll(manifestDir, 0o755))
	manifestPath = filepath.Join(manifestDir, "manifest.json")

	manifest := map[string]any{
		"attempt_id": attemptID,
		"bead_id":    beadID,
		"created_at": time.Now().Add(-2 * time.Hour).Format(time.RFC3339Nano),
		"pid":        pid,
		"requested": map[string]any{
			"harness": "agent",
			"model":   "qwen3.6",
		},
		"bead": map[string]any{
			"id":    beadID,
			"title": "stale worker test",
		},
	}
	data, err := json.Marshal(manifest)
	require.NoError(t, err)
	require.NoError(t, os.WriteFile(manifestPath, data, 0o644))

	return projectRoot, manifestPath, worktreePath
}

// pickDeadPID returns a PID that is almost-certainly not in use. We pick a
// large value above the typical pid_max range and confirm it's dead via
// agentProcessAlive — the test is a no-op on the rare day that PID is live.
func pickDeadPID(t *testing.T) int {
	t.Helper()
	// 999999 is below /proc/sys/kernel/pid_max on most distros (4194304),
	// but well above what a fresh test box has handed out. If it happens
	// to be alive the test is meaningless, so skip rather than mislead.
	candidate := 999999
	if agentProcessAlive(candidate) {
		t.Skipf("PID %d is alive on this host; test cannot establish a dead-PID baseline", candidate)
	}
	return candidate
}

// TestAgentWorkersJSONIncludesPIDAlive (AC4): `ddx agent workers --json`
// reports pid_alive=false for a local worker whose recorded PID is dead, so
// operators can spot stale entries before pruning.
func TestAgentWorkersJSONIncludesPIDAlive(t *testing.T) {
	deadPID := pickDeadPID(t)
	projectRoot, _, _ := initLocalWorkerRepo(t, "ddx-stale-1", "atm-stale-1", deadPID)
	t.Setenv("DDX_DISABLE_UPDATE_CHECK", "1")

	// No server reachable — local scan is the only source. Point at an
	// unreachable URL so fetchServerAgentWorkers fails fast.
	t.Setenv("DDX_SERVER_URL", "http://127.0.0.1:1")

	factory := NewCommandFactory(projectRoot)
	root := factory.NewRootCommand()

	out, err := executeCommand(root, "agent", "workers", "--json", "--project", projectRoot)
	require.NoError(t, err)

	var display []agentWorkerDisplay
	require.NoError(t, json.Unmarshal([]byte(strings.TrimSpace(out)), &display))
	require.Len(t, display, 1)
	got := display[0]
	assert.Equal(t, "local-atm-stale-1", got.ID)
	assert.Equal(t, "stale", got.State, "dead PID must surface as state=stale")
	assert.Equal(t, deadPID, got.PID)
	require.NotNil(t, got.PIDAlive, "pid_alive must be populated when manifest carries a PID")
	assert.False(t, *got.PIDAlive)
}

// TestAgentWorkersPruneRemovesStaleLocalEntries (AC1): `ddx agent workers
// prune` reaps a stale local entry by removing its worktree, after which the
// scan no longer surfaces it.
func TestAgentWorkersPruneRemovesStaleLocalEntries(t *testing.T) {
	deadPID := pickDeadPID(t)
	projectRoot, _, wtPath := initLocalWorkerRepo(t, "ddx-stale-2", "atm-stale-2", deadPID)
	t.Setenv("DDX_DISABLE_UPDATE_CHECK", "1")
	t.Setenv("DDX_SERVER_URL", "http://127.0.0.1:1")

	factory := NewCommandFactory(projectRoot)
	root := factory.NewRootCommand()

	// Sanity: scan finds the stale entry before pruning.
	pre := scanLocalBeadWorkers(projectRoot, nil)
	require.Len(t, pre, 1)

	out, err := executeCommand(root, "agent", "workers", "prune", "--project", projectRoot)
	require.NoError(t, err)
	assert.Contains(t, out, "atm-stale-2")
	assert.Contains(t, out, "pid-dead")

	// Worktree must be gone.
	_, statErr := os.Stat(wtPath)
	assert.True(t, os.IsNotExist(statErr), "prune must remove the worktree")

	// Subsequent scan returns no entries.
	post := scanLocalBeadWorkers(projectRoot, nil)
	assert.Empty(t, post, "prune must clear the registry slot")
}

// TestAgentWorkersPruneDryRun (AC1): --dry-run lists what would be reaped
// without removing the worktree. Confirms operators can preview before they
// commit.
func TestAgentWorkersPruneDryRun(t *testing.T) {
	deadPID := pickDeadPID(t)
	projectRoot, _, wtPath := initLocalWorkerRepo(t, "ddx-stale-3", "atm-stale-3", deadPID)
	t.Setenv("DDX_DISABLE_UPDATE_CHECK", "1")
	t.Setenv("DDX_SERVER_URL", "http://127.0.0.1:1")

	factory := NewCommandFactory(projectRoot)
	root := factory.NewRootCommand()

	out, err := executeCommand(root, "agent", "workers", "prune", "--dry-run", "--project", projectRoot)
	require.NoError(t, err)
	assert.Contains(t, out, "atm-stale-3")
	assert.Contains(t, out, "dry-run")

	// Worktree must still exist after dry-run.
	_, statErr := os.Stat(wtPath)
	assert.NoError(t, statErr, "dry-run must not change anything")
}

// TestAgentWorkersPruneOlderThan (AC1): --older-than reaps entries whose
// started_at exceeds the threshold even if the recorded PID is still alive,
// so weeks-old leakage clears even when a worker process forgot to exit.
func TestAgentWorkersPruneOlderThan(t *testing.T) {
	livePID := os.Getpid() // current process is by definition alive
	projectRoot, _, wtPath := initLocalWorkerRepo(t, "ddx-stale-4", "atm-stale-4", livePID)
	t.Setenv("DDX_DISABLE_UPDATE_CHECK", "1")
	t.Setenv("DDX_SERVER_URL", "http://127.0.0.1:1")

	factory := NewCommandFactory(projectRoot)
	root := factory.NewRootCommand()

	// initLocalWorkerRepo records created_at = now-2h, so 1h matches.
	out, err := executeCommand(root, "agent", "workers", "prune",
		"--older-than", "1h", "--project", projectRoot)
	require.NoError(t, err)
	assert.Contains(t, out, "atm-stale-4")
	assert.Contains(t, out, "older-than")

	_, statErr := os.Stat(wtPath)
	assert.True(t, os.IsNotExist(statErr), "older-than reap must remove the worktree")
}

// TestAgentWorkersStopByBeadHitsStaleLocalEntry (AC2): `ddx agent workers
// stop --bead <id>` succeeds against a stale local registry entry, releasing
// the registry slot rather than returning the historical "no matching
// workers" / "worker not running" deadlock.
func TestAgentWorkersStopByBeadHitsStaleLocalEntry(t *testing.T) {
	deadPID := pickDeadPID(t)
	projectRoot, _, wtPath := initLocalWorkerRepo(t, "ddx-stop-1", "atm-stop-1", deadPID)
	t.Setenv("DDX_DISABLE_UPDATE_CHECK", "1")
	t.Setenv("DDX_SERVER_URL", "http://127.0.0.1:1")

