// TestAgentWorkersStopByIDHitsStaleLocalEntry (AC2): same as above but via
// the explicit worker id path.
func TestAgentWorkersStopByIDHitsStaleLocalEntry(t *testing.T) {
	deadPID := pickDeadPID(t)
