// staleServerStub serves a worker whose state is "running" but whose stop
// endpoint returns 400 "worker not running" — exactly the contradiction the
// bug report describes. The CLI is expected to treat that 400 as a stale
// stop and report success.
type staleServerStub struct {
	mu       sync.Mutex
	stopCall string
}

func newStaleServerStub(t *testing.T, workers []map[string]any) (*staleServerStub, *httptest.Server) {
	t.Helper()
	s := &staleServerStub{}
	mux := http.NewServeMux()
	mux.HandleFunc("GET /api/agent/workers", func(w http.ResponseWriter, _ *http.Request) {
		w.Header().Set("Content-Type", "application/json")
		_ = json.NewEncoder(w).Encode(workers)
	})
	mux.HandleFunc("POST /api/agent/workers/{id}/stop", func(w http.ResponseWriter, r *http.Request) {
		s.mu.Lock()
		s.stopCall = r.PathValue("id")
		s.mu.Unlock()
		w.WriteHeader(http.StatusBadRequest)
		_, _ = w.Write([]byte(`{"error":"worker not running"}`))
	})
	srv := httptest.NewServer(mux)
	t.Cleanup(srv.Close)
	return s, srv
}

// TestAgentWorkersStopTreatsServerWorkerNotRunningAsSuccess (AC2): when the
// server responds 400 "worker not running" for a record whose registry still
// reads running, the CLI returns success — that's the exact contradiction
// the bug report flags.
func TestAgentWorkersStopTreatsServerWorkerNotRunningAsSuccess(t *testing.T) {
	workers := []map[string]any{
		{
			"id":    "worker-orphan",
			"kind":  "execute-loop",
			"state": "running",
			"current_attempt": map[string]any{
				"attempt_id": "atm-orphan",
				"bead_id":    "ddx-stale-server",
			},
		},
	}
	stub, srv := newStaleServerStub(t, workers)
	t.Setenv("DDX_SERVER_URL", srv.URL)
	t.Setenv("DDX_DISABLE_UPDATE_CHECK", "1")

	factory := NewCommandFactory(t.TempDir())
	root := factory.NewRootCommand()

	out, err := executeCommand(root, "agent", "workers", "stop",
		"--bead", "ddx-stale-server")
	require.NoError(t, err, "stop must report success when server says 'worker not running'")
	assert.Contains(t, out, "stopping worker-orphan")

	stub.mu.Lock()
	defer stub.mu.Unlock()
	assert.Equal(t, "worker-orphan", stub.stopCall, "stop endpoint must still be hit so the server can rewrite its record")
}

// TestStopServerWorkerSwallowsNotRunning is a focused unit test for the
// shared helper used by both stop and prune. Keeps the contract documented
// even if the higher-level flow tests change.
func TestStopServerWorkerSwallowsNotRunning(t *testing.T) {
	mux := http.NewServeMux()
	mux.HandleFunc("POST /api/agent/workers/{id}/stop", func(w http.ResponseWriter, _ *http.Request) {
		w.WriteHeader(http.StatusBadRequest)
		_, _ = w.Write([]byte(`{"error":"worker not running"}`))
	})
	srv := httptest.NewServer(mux)
	t.Cleanup(srv.Close)
	t.Setenv("DDX_SERVER_URL", srv.URL)

	err := stopServerWorker(context.Background(), t.TempDir(), "worker-x")
	assert.NoError(t, err, "'worker not running' must not surface as an error to operators")
}

