package server

import (
	"encoding/json"
	"os"
	"path/filepath"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// pickDeadPID returns a PID that should not map to any live process. Used
// by reconciliation tests to write a status.json that looks running but
// whose process has gone. Skips when the candidate happens to be alive on
// this host so the test stays meaningful.
func pickDeadPID(t *testing.T) int {
	t.Helper()
	candidate := 999998
	if processAlive(candidate) {
		t.Skipf("PID %d is alive on this host; reconciliation test cannot establish a dead-PID baseline", candidate)
	}
	return candidate
}

// writeRunningRecord seeds a status.json that says state=running but whose
// recorded PID is dead — the on-disk shape that an abnormal exit leaves
// behind.
func writeRunningRecord(t *testing.T, m *WorkerManager, id string, deadPID int, beadID string) {
	t.Helper()
	dir := filepath.Join(m.rootDir, id)
	require.NoError(t, os.MkdirAll(dir, 0o755))
	rec := WorkerRecord{
		ID:          id,
		Kind:        "execute-loop",
		State:       "running",
		Status:      "running",
		ProjectRoot: m.projectRoot,
		StartedAt:   time.Now().Add(-2 * time.Hour).UTC(),
		PID:         deadPID,
		Lifecycle: []WorkerLifecycleEvent{{
			Action:    "start",
			Actor:     "local-operator",
			Timestamp: time.Now().Add(-2 * time.Hour).UTC(),
		}},
	}
	if beadID != "" {
		rec.CurrentAttempt = &CurrentAttemptInfo{
			AttemptID: "atm-" + id,
			BeadID:    beadID,
			Phase:     "running",
		}
	}
	data, err := json.MarshalIndent(rec, "", "  ")
	require.NoError(t, err)
	require.NoError(t, os.WriteFile(filepath.Join(dir, "status.json"), data, 0o644))
}

// TestReconcileOnStartupDowngradesOrphans (AC3): a status.json that says
// running but whose PID is dead must be rewritten to state=orphaned at
// manager construction. Without this, every server restart leaves
// pre-restart records advertising themselves as running with elapsed_ms
// ticking upward — the exact bug pattern from the issue report.
func TestReconcileOnStartupDowngradesOrphans(t *testing.T) {
	root := t.TempDir()
	setupBeadStore(t, root)
	deadPID := pickDeadPID(t)

	// Stage the orphan record first, then construct the manager so the
	// constructor's reconciliation pass sees it.
	staging := &WorkerManager{
		projectRoot: root,
		rootDir:     filepath.Join(root, ".ddx", "workers"),
	}
	writeRunningRecord(t, staging, "worker-orphan", deadPID, "")

	m := NewWorkerManager(root)
	defer m.StopWatchdog()

	rec, err := m.Show("worker-orphan")
	require.NoError(t, err)
	assert.Equal(t, "orphaned", rec.State, "dead-PID record must be downgraded to orphaned")
	assert.Equal(t, "orphaned", rec.Status)
	assert.False(t, rec.FinishedAt.IsZero(), "orphan record must stamp FinishedAt")
	require.NotEmpty(t, rec.Lifecycle)
	last := rec.Lifecycle[len(rec.Lifecycle)-1]
	assert.Equal(t, "reconcile", last.Action)
	assert.Equal(t, "ddx-server", last.Actor)
}

// TestReconcileOnStartupKeepsLivePID (AC3): a record whose PID is still
// alive (a worker that survived us — escaped this manager's control) is
// left as-is so the operator can investigate, rather than being silently
// downgraded to orphaned.
func TestReconcileOnStartupKeepsLivePID(t *testing.T) {
	root := t.TempDir()
	setupBeadStore(t, root)

	staging := &WorkerManager{
		projectRoot: root,
		rootDir:     filepath.Join(root, ".ddx", "workers"),
	}
	livePID := os.Getpid()
	writeRunningRecord(t, staging, "worker-live", livePID, "")

	m := NewWorkerManager(root)
	defer m.StopWatchdog()

	rec, err := m.Show("worker-live")
	require.NoError(t, err)
	assert.Equal(t, "running", rec.State, "live-PID record must be left alone")
}

// TestStopReconcilesStaleRecord (AC2): WorkerManager.Stop on a worker whose
// in-memory handle is gone but whose status.json says running succeeds —
// it rewrites the persisted record to stopped and releases any held bead
// claim, instead of returning the historical "worker not running" error.
func TestStopReconcilesStaleRecord(t *testing.T) {
	root := t.TempDir()
	setupBeadStore(t, root)
	deadPID := pickDeadPID(t)

	// Seed a claimed bead so we can verify the claim is released.
	store := bead.NewStore(filepath.Join(root, ".ddx"))
	require.NoError(t, store.Create(&bead.Bead{
		ID:    "ddx-orphan-claim",
		Title: "stale claim test",
	}))
	require.NoError(t, store.Claim("ddx-orphan-claim", "worker-orphan-2"))

	// Stage the record. Construct the manager *afterwards* but with an
	// empty workers map so the in-memory handle is missing — that's the
	// state that triggered the bug.
	staging := &WorkerManager{
		projectRoot: root,
		rootDir:     filepath.Join(root, ".ddx", "workers"),
	}
	writeRunningRecord(t, staging, "worker-orphan-2", deadPID, "ddx-orphan-claim")

	// We don't want NewWorkerManager's startup reconciliation to claim
	// this case first — it would mark orphaned which is also a non-running
	// state and Stop would early-return success. To target the Stop path
	// explicitly, manually flip back to running after construction.
	m := NewWorkerManager(root)
	defer m.StopWatchdog()
	staging.rootDir = m.rootDir
	writeRunningRecord(t, staging, "worker-orphan-2", deadPID, "ddx-orphan-claim")

	require.NoError(t, m.Stop("worker-orphan-2"),
		"Stop must reconcile a stale record instead of erroring")

	rec, err := m.Show("worker-orphan-2")
	require.NoError(t, err)
	assert.Equal(t, "stopped", rec.State)
	assert.Equal(t, "stopped", rec.Status)
	assert.False(t, rec.FinishedAt.IsZero())

	// Bead claim must be released.
	b, err := store.Get("ddx-orphan-claim")
	require.NoError(t, err)
	assert.Empty(t, b.Owner, "stale Stop must release the bead claim")
}

// TestStopRefusesLivePIDOrphan: a worker that's missing from the in-memory
// map but whose recorded PID is still alive must NOT be reconciled by
// Stop — that would silently release a real worker's bead claim out from
// under it. Operators see the original "worker not running" error so they
// investigate before forcing the issue.
func TestStopRefusesLivePIDOrphan(t *testing.T) {
	root := t.TempDir()
	setupBeadStore(t, root)

	staging := &WorkerManager{
		projectRoot: root,
		rootDir:     filepath.Join(root, ".ddx", "workers"),
	}
	livePID := os.Getpid()
	writeRunningRecord(t, staging, "worker-orphan-live", livePID, "")

	m := &WorkerManager{
		projectRoot:      root,
		rootDir:          filepath.Join(root, ".ddx", "workers"),
		workers:          map[string]*workerHandle{},
		LandCoordinators: newCoordinatorRegistry(),
		watchdogStop:     make(chan struct{}),
	}

	err := m.Stop("worker-orphan-live")
	require.Error(t, err, "Stop must refuse to reconcile a record whose PID is still alive")
}

